package main

import (
	"html/template"
	"net/http"
	"encoding/json"
	"strings"
	"text/template/parse"
	"github.com/kisielk/safehtml"
)

type Comment struct {
	ID      int    `json:"id"`
	Content string `json:"content"`
}

var comments = []Comment{
	{ID: 1, Content: "Hello, **world**!"},
	{ID: 2, Content: "This is an *italic* comment."},
}

func main() {
	tmpl := template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Comments</title>
</head>
<body>
    <h1>User Comments</h1>
    {{range .}}
        <div>{{safeHTML .Content | toHTML }}</div>
    {{end}}
</body>
</html>
`))

	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		err := tmpl.ExecuteTemplate(w, "comments", comments)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		}
	})

	http.ListenAndServe(":8080", nil)
}

func toHTML(s string) template.HTML {
	sanitizer := safehtml.NewLenientWhitelist("b", "i")
	return template.HTML(sanitizer.Sanitize(strings.ReplaceAll(s, "<", "&lt;"), strings.ReplaceAll(s, ">", "&gt;")))
}